type UnionFind struct {
    parent []int64
    rank   []int64
    count  int64
}

func NewUnionFind(n int64) *UnionFind {
    parent := make([]int64, n)
    rank := make([]int64, n)
    for i := int64(0); i < n; i++ {
        parent[i] = i
        rank[i] = 1
    }
    return &UnionFind{
        parent: parent,
        rank:   rank,
        count:  n,
    }
}

func (uf *UnionFind) Find(x int64) int64 {
    if uf.parent[x] != x {
        uf.parent[x] = uf.Find(uf.parent[x])
    }
    return uf.parent[x]
}

func (uf *UnionFind) Union(x, y int64) {
    xroot := uf.Find(x)
    yroot := uf.Find(y)
    if xroot == yroot {
        return
    }
    if uf.rank[xroot] < uf.rank[yroot] {
        uf.parent[xroot] = yroot
    } else {
        uf.parent[yroot] = xroot
        uf.rank[xroot] += uf.rank[yroot]
    }
    uf.count--
}

func solve(n int64, edges [][]int64, k int64) int64 {
    if len(edges) == 0 {
        return 0
    }
    max_w := 0
    for _, edge := range edges {
        if edge[2] > max_w {
            max_w = edge[2]
        }
    }
    low := 0
    high := max_w
    result := max_w
    for low <= high {
        mid := (low + high) / 2
        uf := NewUnionFind(n)
        for _, edge := range edges {
            if edge[2] <= mid {
                uf.Union(edge[0], edge[1])
            }
        }
        if uf.count <= k {
            result = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    return result
}
